#include<bits/stdc++.h>
using namespace std;
int ans=0,maxans=0,maxans2=0,n;
int maxxans=0;
vector<int> e[100005];
bool v[100005];
bool x[100005];
void dfs(int x,int step){
    if(step>maxans){
        maxans=step;
        ans=x;
    }
    v[x]=1;
    for(int i=0;i<e[x].size();i++){
        if(!v[e[x][i]]){
           dfs(e[x][i],step+1); 
        }
    }
    v[x]=0;
    return;
}
void dfs2(int x,int step){
    if(step>maxans2){
        maxans2=step;
    }
    v[x]=1;
    for(int i=0;i<e[x].size();i++){
        if(!v[e[x][i]]){
           dfs2(e[x][i],step+1); 
        }
    }
    return;
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++) cin>>x[i];
    for(int i=1;i<=n-1;i++){
        int xx,yy;
        cin>>xx>>yy;
        if(x[xx]!=x[yy]){
            e[xx].push_back(yy);
            e[yy].push_back(xx);
        }
    }
    for(int i=1;i<=n;i++){
        if(!v[i]){
            ans=0;
            maxans=0;
            maxans2=0;
            dfs(i,1);
            dfs2(ans,1);
            if(maxxans<maxans2) maxxans=maxans2;
        }
    }
    cout<<maxxans;
    return 0;
}
